 	nfc_sc = device_get_softc(nfc);

-	mtx_init(&sc->nandbus_mtx, "nandbus lock", MTX_DEF, 0);
+	mtx_init(&sc->nandbus_mtx, "nandbus lock", NULL, MTX_DEF);
